// Per-utility metadata: inline citation (spec-v2 5.1), test-with-example
// values (spec-v2 5.3), and primary data source for the inline source stamp
// (spec-v2 5.2).
//
// The router renders these in a uniform block above each utility body, so
// the citation, example, and source stamp are present and styled the same
// way on every view without each renderer having to remember to add them.

// spec-v61 A1: clamp an Epworth situational-sleepiness rating to 0-3, matching
// epworthClamp() in lib/scoring-v4.js so the derivation component sum reproduces
// the live Epworth score exactly.
function essClamp(v) {
  const n = Math.round(Number(v));
  if (!Number.isFinite(n) || n < 0) return 0;
  return n > 3 ? 3 : n;
}

// spec-v61 A1 wave 4: clamp a 0-2 per-sign rating for the additive
// "five signs, 0-2 each" bedside scores (APGAR, Silverman-Andersen, Downes).
// In-range integer inputs are returned unchanged, so the derivation component
// sum reproduces the live total exactly; out-of-range input is clamped so the
// show-your-work panel never renders NaN.
function sign02Clamp(v) {
  const n = Math.round(Number(v));
  if (!Number.isFinite(n) || n < 0) return 0;
  return n > 2 ? 2 : n;
}

// spec-v61 A1 wave 10: build derivation components for the array-scored brief
// screeners (AUDIT, DAST-10, GDS-15). Each item is keyed q1..qN so the renderer
// can pass an inputs object (or array, since arr[i] === arr['i']) and the
// component sum reproduces the live total. `reverse` lists the 1-indexed items
// that score on "No" (1 when unchecked), mirroring the scoring functions exactly.
function yesNoItems(labels, reverse = []) {
  const rev = new Set(reverse);
  return labels.map((label, i) => ({
    inputKey: `q${i + 1}`,
    label,
    points: rev.has(i + 1) ? (v) => (v ? 0 : 1) : 1,
  }));
}
// Ordinal (0-N) screener items keyed q1..qN; the item value is its own points.
function ordinalItems(labels) {
  return labels.map((label, i) => ({
    inputKey: `q${i + 1}`,
    label,
    points: (v) => Number(v) || 0,
  }));
}
// units object {q1: unit, ... qN: unit} covering every generated component key.
function screenerUnits(n, unit) {
  const u = {};
  for (let i = 1; i <= n; i += 1) u[`q${i}`] = unit;
  return u;
}

// spec-v61 A1 wave 12: age-band tables for the pediatric organ-dysfunction
// scores (PELOD-2, pSOFA). These MIRROR lib/scoring-v6.js (ageBandIndex,
// PELOD2_MAP/PELOD2_CREAT, PSOFA_MAP/PSOFA_CREAT); meta.js is import-free by
// design, so they are replicated here and the derivation.test.js cross-checks
// (which compare the component sum against the live score across age bands) fail
// loudly if these ever drift from the scoring module.
function pelodAgeBand(ageMonths) {
  const a = Number(ageMonths);
  if (!(a >= 0)) return 0;
  if (a < 1) return 0;
  if (a < 12) return 1;
  if (a < 24) return 2;
  if (a < 60) return 3;
  if (a < 144) return 4;
  return 5;
}
const D_PELOD2_MAP = [
  { c0: 46, c2: 31, c3: 17 }, { c0: 55, c2: 39, c3: 25 }, { c0: 60, c2: 44, c3: 31 },
  { c0: 62, c2: 46, c3: 32 }, { c0: 65, c2: 49, c3: 36 }, { c0: 67, c2: 52, c3: 38 },
];
const D_PELOD2_CREAT = [70, 23, 35, 51, 59, 93];
const D_PSOFA_MAP = [46, 55, 60, 62, 65, 67];
const D_PSOFA_CREAT = [
  [0.8, 1.0, 1.2, 1.6], [0.3, 0.5, 0.7, 1.2], [0.4, 0.6, 1.1, 1.5],
  [0.6, 0.9, 1.6, 2.3], [0.7, 1.1, 1.8, 2.6], [1.0, 1.7, 2.9, 4.2],
];

// spec-v61 A1: APACHE II acute-physiology step lookup, mirroring apsStep() in
// lib/scoring-v6.js so the derivation per-variable points reproduce the live
// score; the derivation.test.js cross-checks fail if the breaks drift.
function apsStep(v, breaks) {
  const n = Number(v);
  for (const [lo, hi, pts] of breaks) if (n >= lo && n <= hi) return pts;
  return 0;
}

// spec-v61 A1: build derivation components for the Finnegan NAS weighted-binary
// signs from [inputKey, label, weight] rows (a present sign contributes `weight`).
// The weights mirror FINNEGAN_WEIGHTS in lib/scoring-v6.js; the cross-checks in
// derivation.test.js fail if a weight drifts.
function weightedBinaryItems(rows) {
  return rows.map(([inputKey, label, points]) => ({ inputKey, label, points }));
}

