  // staleness row is warranted (spec-v92/v94 ISSUER_PATTERN lesson).
  'peds-bmi-percentile': {
    citation: 'Kuczmarski RJ, Ogden CL, Guo SS, et al. 2000 CDC growth charts for the United States: methods and development. Vital Health Stat 11. 2002;(246):1-190.',
    citationUrl: 'https://www.cdc.gov/nchs/data/series/sr_11/sr11_246.pdf',
    citationAccessed: '2026-06-23',
    specialties: ['pediatrics', 'family-medicine', 'nutrition', 'nursing-peds'],
    example: { fields: { 'bm-sex': 'male', 'bm-age': '16', 'bm-bmi': '30' },
               expected: 'BMI 30 kg/m² at age 16 y: 98th percentile (z 1.97) — obese (95th percentile or above).' },
    interpretation: {
      sourceQuoted: true,
      sourceCitation: 'Pediatric BMI-for-age (2000 CDC growth charts; Kuczmarski 2002).',
      bands: [
        { range: 'Transform', text: 'the BMI is converted to an age- and sex-specific z-score by the CDC LMS transform z = ((BMI/M)^L − 1) / (L·S); the percentile is the standard-normal CDF of z.' },
        { range: 'Bands', text: 'under the 5th percentile underweight; 5th to under the 85th healthy weight; 85th to under the 95th overweight; 95th percentile or above obese.' },
        { range: 'Range', text: 'BMI-for-age applies to ages 2 to 20 years; below 2 use the WHO weight/length-for-age tool.' },
      ],
    },
    related: ['who-growth-zscore', 'bmi', 'peds-weight-conv'],
  },
