  'start-triage':     { citation: 'Super G, et al. START: Simple Triage and Rapid Treatment. Newport Beach Fire Department / Hoag Hospital, 1983. Public-domain MCI triage protocol.',
                        source: { dataset: 'mci-triage', label: 'START / JumpSTART algorithm reference' },
                        example: { fields: { 'st-walk': '1' }, expected: 'Minor (green): patient can walk.' } },
  'jumpstart-triage': { citation: 'Romig LE. JumpSTART pediatric MCI triage tool. CHOC Children\'s Hospital. Public-domain pediatric variant of START.',
                        source: { dataset: 'mci-triage', label: 'START / JumpSTART algorithm reference' },
                        example: { fields: { 'js-walk': '1' }, expected: 'Minor (green): child can walk.' } },
  bsa_burn:           { citation: 'Lund CC, Browder NC. The estimation of areas of burns. Surg Gynecol Obstet. 1944;79:352-358. Rule of Nines: standard adult body-region distribution.',
                        example: { fields: { 'bb-method': 'nines', 'bb-n-trunk-anterior': '1' }, expected: 'TBSA 18% (anterior trunk only).' } },
  'burn-fluid':       { citation: 'Baxter CR, Shires T. Physiological response to crystalloid resuscitation of severe burns. Ann N Y Acad Sci. 1968;150(3):874-894 (Parkland). Reiss E, et al. Modified Brooke formula.',
                        example: { fields: { 'bf-w': '70', 'bf-bsa': '20', 'bf-h': '0' }, expected: 'Parkland 5600 mL/24h (2800 mL first 8h); Brooke 2800 mL/24h.' },
                        // spec-v62 §2 A5: substituted-formula derivation (both formulas).
                        derivation: {
                          formula: 'Parkland: total 24h fluid (mL) = 4 mL x weight(kg) x %TBSA\nModified Brooke: total 24h fluid (mL) = 2 mL x weight(kg) x %TBSA\n  Half is given over the first 8 h (from the time of injury), half over the next 16 h.',
                          substituted: (inputs) => {
                            const w = Number(inputs && inputs.weightKg);
                            const tbsa = Number(inputs && inputs.tbsaPercent);
                            if (![w, tbsa].every(Number.isFinite) || w <= 0 || tbsa <= 0) return null;
                            const r2 = (x) => Math.round(x * 100) / 100;
                            const pk = 4 * w * tbsa;
                            const br = 2 * w * tbsa;
                            if (![pk, br].every(Number.isFinite)) return null;
                            const pkHalf = r2(pk / 2);
                            return `Parkland = 4 mL x ${w} kg x ${tbsa}% = ${r2(pk)} mL/24h; first 8h = ${pkHalf} mL (${r2(pkHalf / 8)} mL/hr), next 16h = ${pkHalf} mL\nModified Brooke = 2 mL x ${w} kg x ${tbsa}% = ${r2(br)} mL/24h`;
                          },
                          population: 'Baxter & Shires 1968 (Parkland), derived in adult burn patients resuscitated with lactated Ringer; the modified Brooke (Reiss) halves the crystalloid volume. Both are starting-point estimates titrated to urine output (0.5 mL/kg/hr in adults).',
                          units: { weightKg: 'kg', tbsaPercent: '% total body surface area (second-degree and deeper)' },
                          validity: 'Estimates the first-24-hour crystalloid resuscitation volume for thermal burns from the time of injury, not the time of presentation. It is a starting estimate only; actual rate is titrated to urine output and hemodynamics, and the formulas over-resuscitate in inhalation injury, electrical burns, and delayed presentation. Pediatric and high-TBSA burns need a maintenance addition and specialist input.',
                          source: 'Baxter CR, Shires T. "Physiological response to crystalloid resuscitation of severe burns." Ann N Y Acad Sci. 1968;150(3):874-894.',
                        } },
