      formula: 'CRIES = sum of 5 items, each 0-2 (0-10):\n  Crying\n  Requires O2 for SaO2 <95%\n  Increased vital signs\n  Expression\n  Sleeplessness\nBands: <4 no significant pain; 4-6 moderate (analgesia indicated); >=7 severe.',
      components: [
        { inputKey: 'crying', label: 'Crying (0-2)', points: (v) => Number(v) || 0 },
        { inputKey: 'requiresO2', label: 'Requires O2 for SaO2 <95% (0-2)', points: (v) => Number(v) || 0 },
        { inputKey: 'vitals', label: 'Increased vital signs (0-2)', points: (v) => Number(v) || 0 },
        { inputKey: 'expression', label: 'Expression (0-2)', points: (v) => Number(v) || 0 },
        { inputKey: 'sleeplessness', label: 'Sleeplessness (0-2)', points: (v) => Number(v) || 0 },
      ],
      bands: [
        { range: { op: '<', value: 4 }, label: 'no significant pain (<4)' },
        { range: [4, 6], label: 'moderate pain — analgesia indicated (4-6)' },
        { range: { op: '>=', value: 7 }, label: 'severe pain (>=7)' },
      ],
      population: 'Developed for postoperative pain in neonates (Krechel & Bildner 1995); five physiologic/behavioral items (Crying, Requires O2, Increased vitals, Expression, Sleeplessness).',
      units: { crying: '0-2', requiresO2: '0-2', vitals: '0-2', expression: '0-2', sleeplessness: '0-2' },
      validity: 'Assesses postoperative pain in neonates; a score >=4 indicates a need for analgesia. It is a behavioral/physiologic observation, not a continuous monitor, and the vital-sign item assumes a known baseline.',
      source: 'Krechel SW, Bildner J. CRIES: a new neonatal postoperative pain measurement score. Initial testing of validity and reliability. Paediatr Anaesth. 1995;5(1):53-61.',
